INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (1, 'An author, speaker, and apologist who analyzes historical Christian theology with a specific emphasis on evaluating and critiquing progressive Christianity and modern cultural shifts.', 'Apologist, Author, Speaker, Podcaster, Musician', 'Self-taught Christian Apologetics, mentored by Southern Evangelical Seminary faculty');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (2, 'A Christian speaker, author, and ordained minister who provides biblical teaching and commentary focused on spiritual growth, theology, and church practices.', 'Speaker, Author, Ordained Minister, Bible Teacher', 'Master of Theology (Th.M.) from Dallas Theological Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (3, 'A researcher and podcaster operating within a reformed theological framework who focuses on historical analysis and critique of alternative religious movements, esoteric groups, and cults.', 'Researcher, Podcaster, Reformed Apologist', 'Theological & Historical Studies (Apologia Church training/self-taught researcher)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (4, 'A podcaster and commentator who discusses her personal transition from New Age spirituality to conservative Christian theology, offering a critique of modern spiritualism.', 'Christian Podcaster, Commentator', 'Self-taught Christian Apologetics & New Age Research');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (5, 'A minister and leader of the Five-Fold Church who conducts public revival services centered on charismatic practices, faith healing, and deliverance ministry.', 'Revivalist, Evangelist, Lead Pastor of Five-Fold Church', 'Bachelor of Arts in Theater and Music from University of Miami');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (6, 'A pastor, author, and apologist holding advanced degrees in theology and philosophy, specializing in addressing intellectual doubts and pastoral care for those experiencing faith crises.', 'Pastor, Author, Apologist', 'Ph.D. in Philosophy of Religion from the University of Birmingham, Doctor of Ministry (D.Min.) from Southern Evangelical Seminary, Master of Theology (Th.M.) from Dallas Theological Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (7, 'An apologist and writer focused on cultural engagement, worldview analysis, and making classical apologetics accessible to general audiences.', 'Writer, Apologist, Ministry Director', 'Master of Arts in Christian Apologetics from Biola University, B.S. in Journalism from Michigan State University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (8, 'A filmmaker and digital content creator who produces analytical commentary on philosophical and theological arguments regarding theism and Christianity.', 'Filmmaker, Director, Digital Creator', 'B.A. in Communications from University of South Florida');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (9, 'A lifestyle vlogger and digital creator who shares commentary regarding her personal religious transition, targeting lifestyle and modesty themes for young Christian women.', 'Lifestyle Vlogger, Digital Influencer', 'Studied at Texas Tech University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (10, 'An evangelist and digital creator who records and publishes unscripted public interactions concerning religious faith and personal beliefs.', 'Street Evangelist, Videographer', 'Evangelism & Youth Ministry Training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (11, 'A professional photographer and classical apologist who converted to Catholicism, known for hosting structured academic debates and philosophical inquiries into theism.', 'Photographer, Classical Apologist, Founder of Capturing Christianity', 'Bachelor of Arts from Capturing Christianity/Photography/Design studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (12, 'An evangelical pastor and apologist who conducts open-air dialogue sessions with university students, focusing on answering direct objections to Christian theology.', 'Evangelical Pastor, Campus Apologist, Author', 'Master of Divinity (M.Div.) from Trinity Evangelical Divinity School, B.A. from Davidson College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (13, 'An evangelist and founder of The Next Generation Ministries who practices public charismatic deliverance and spiritual warfare ministry across diverse urban environments.', 'Evangelist, Deliverance Minister, Founder of The Next Generation Ministries', 'Ministerial ordination & Charismatic theology training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (14, 'A polemical apologist and philosopher specializing in comparative religion, with an extensive body of work analyzing and critiquing Islamic theology, texts, and historical claims.', 'Philosopher, Apologist, Polemicist', 'Ph.D. in Philosophy from Fordham University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (15, 'A former prominent New Age author and speaker who converted to biblical Christianity and now produces material analyzing the theological errors of modern occultism and alternative spirituality.', 'Author, Speaker, Apologist (former New Age author)', 'M.A. in Counseling Psychology from Chapman University, B.A. from Chapman University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (16, 'An author, speaker, and cross-examination apologist who presents scientific, historical, and logical arguments in defense of the core tenets of Christianity.', 'Author, Speaker, Apologist, President of CrossExamined.org', 'Doctor of Ministry (D.Min.) from Southern Evangelical Seminary, Master of Public Administration from George Washington University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (17, 'A reformed pastor, theologian, and author who engages in historical retrieval and scholarly ecumenical dialogue concerning church history and protestant apologetics.', 'Reformed Pastor, Theologian, Author, Scholar', 'Ph.D. in Historical Theology from Fuller Theological Seminary, M.Div. from Covenant Theological Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (18, 'An ordained minister, evangelist, and director of Speak Life who uses creative media and cultural analysis to articulate the Christian roots of modern Western ideals.', 'Ordained Anglican Minister, Evangelist, Director of Speak Life', 'Studied Theology at Wycliffe Hall, Oxford University; B.A. from University of Canberra');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (19, 'A veteran Christian apologist, author, and founder of Stand to Reason who focuses on developing analytical thinking and conversational tactics for worldview diplomacy.', 'Apologist, Author, Founder and President of Stand to Reason', 'Master of Arts in Philosophy from University of Southern California, Master of Arts in Christian Apologetics from Biola University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (20, 'The lead pastor of Global Vision Bible Church who delivers regular expository preaching heavily inflected with political commentary, social critique, and charismatic deliverance practice.', 'Lead Pastor of Global Vision Bible Church, Evangelist, Author', 'B.A. in Biblical Studies from Ambassador Baptist College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (21, 'A charismatic speaker and podcaster who advocates for modern church revivals through an emphasis on deliverance ministry, casting out demons, and fasting.', 'Charismatic Speaker, Podcaster, Deliverance Minister', 'Ministerial and theological self-training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (22, 'A retired cold-case homicide detective and Christian apologist who applies standard professional forensic investigation methodologies to historical biblical manuscripts and the resurrection accounts.', 'Cold-Case Homicide Detective, Apologist, Author, Professor', 'Master of Arts in Theological Studies from Golden Gate Baptist Theological Seminary, B.S. in Design from California State University, Long Beach');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (23, 'A former occult practitioner and current Christian commentator who documents her experiences within dark spiritualism and provides theological critiques of modern witchcraft.', 'Christian Commentator, Podcaster (former occultist)', 'Biblical hermeneutics and spiritualism self-training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (24, 'A reformed pastor, elder at Apologia Church, and anti-abortion activist who specializes in presuppositional apologetics and local political advocacy.', 'Reformed Pastor (Apologia Church), Apologist, Political Activist', 'Theological studies at New England Bible College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (25, 'An author, researcher, and co-host of the Cultish podcast who operates within the Apologia Studios network to analyze the history, sociological behaviors, and rhetoric of alternative religious systems.', 'Researcher, Author, Podcaster (co-host of Cultish)', 'Biblical studies and cult analysis training (Apologia Church elder program)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (26, 'A former professional psychic medium who spent years operating within spiritualist frameworks before converting to Christianity; her work focuses on critiquing divination and alternative spiritualities.', 'Author, Speaker, Apologist (former professional psychic)', 'Christian apologetics and biblical studies self-training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (27, 'A media producer and scriptwriter who constructs cinematic documentary-style analyses exploring ancient biblical prophecy, eschatology, and worldview trends.', 'Media Producer, Scriptwriter, Founder of AoC Network', 'Digital Media Production and Theology studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (28, 'An associate apologist and cold-case investigator who collaborates on developing forensic frameworks to cross-examine historical narratives surrounding early Christian records.', 'Cold-Case Investigator, Apologist, Speaker', 'Criminal Justice and Forensic Criminology studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (29, 'A street evangelist and cultural commentator based in the UK who analyzes contemporary social developments and high-profile secular news events through an evangelical lens.', 'Street Evangelist, Cultural Commentator (UK)', 'Theological and evangelistic studies (UK biblical programs)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (30, 'The lead pastor of Blessed Hope Chapel and director of Good Fight Ministries, known for producing extensive investigative critiques regarding the subtext and spiritual alignment of Hollywood cinema and popular music.', 'Lead Pastor of Blessed Hope Chapel, Director of Good Fight Ministries', 'Pastoral theology and Biblical studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (31, 'An emeritus professor of mathematics at the University of Oxford, bioethicist, and internationally prominent Christian philosopher who writes and speaks extensively on the interface between science, mathematics, and philosophy of religion.', 'Professor Emeritus of Mathematics (Oxford), Philosopher of Science, Author', 'Ph.D. in Mathematics from University of Cambridge, D.Sc. from University of Cardiff, D.Phil. from University of Oxford');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (32, 'A prominent reformed theologian, author, chancellor of Bethlehem College & Seminary, and founder of Desiring God, known for articulating a theological system termed ''Christian Hedonism.''', 'Reformed Theologian, Author, Chancellor of Bethlehem College & Seminary', 'Ph.D. in New Testament Studies from University of Munich, B.D. from Fuller Theological Seminary, B.A. from Wheaton College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (33, 'A creative visual communicator and co-founder of BibleProject who specializes in structuring dense historical and literary data into narrative concepts for animation.', 'Creative Director, Visual Communicator, Co-Founder of BibleProject', 'B.A. in Biblical Studies from Multnomah University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (34, 'A digital apologist and cultural commentator who analyzes internet culture, modern philosophy, and popular secular memes to address common contemporary objections to faith.', 'Digital Apologist, Cultural Commentator', 'B.A. in Philosophy or similar studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (35, 'A British broadcaster, journalist, and author who spent over a decade hosting formal public dialogues and structured debates between world-class theologians, philosophers, scientists, and high-profile secular thinkers.', 'Broadcaster, Journalist, Author, Moderator', 'Studied Philosophy and Theology at Oxford University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (36, 'A young-earth creationist author, speaker, and founder of Answers in Genesis, the Creation Museum, and the Ark Encounter who argues for strict literal biblical authority regarding the origins of life and earth.', 'Author, Speaker, President/Founder of Answers in Genesis', 'Bachelor of Applied Science in Environmental Biology from Queensland Institute of Technology, Diploma of Education from University of Queensland');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (37, 'A digital creator and commentator who documents her personal departure from New Age alternative networks, offering structural critiques of contemporary spiritualism.', 'Digital Creator, Commentator (ex-New Age)', 'Christian apologetics and theology self-training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (38, 'A military veteran, Christian author, and independent minister who produces high-frequency reaction videos analyzing entertainment media and modern political environments through a spiritual warfare lens.', 'Minister, Author, Military Veteran', 'High school graduate, military leadership training');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (39, 'An Australian Catholic author, apologist, and philosopher who hosts long-form philosophical discussions exploring classical Thomism, Catholic theology, and cultural issues.', 'Catholic Author, Apologist, Podcaster (Pints with Aquinas)', 'Master''s Degree in Philosophy from Holy Apostles College and Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (40, 'An apologist and creative content creator who specializes in the study of alternative religious movements and counter-cult apologetics, frequently utilizing satirical sketches to critique esoteric theological trends.', 'Apologist, Speaker, Creative Content Creator', 'B.A. in Religious Studies from Southern Evangelical Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (41, 'A digital researcher and apologist who manages InspiringPhilosophy, producing highly detailed, structured visual arguments focusing on biblical archeology, historical criticism, and philosophy of religion.', 'Digital Apologist, Researcher, Founder of InspiringPhilosophy', 'Master of Arts in Christian Apologetics from Biola University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (42, 'A Catholic theologian and researcher specializing in Eastern Christian history, magisterial authority, and canon law who provides systematic reviews of contemporary Catholic current events.', 'Catholic Theologian, Canon Law Researcher', 'Ph.D. candidate in Theology at Pontifical University of St. Thomas Aquinas (Angelicum), M.A. in Theology from Christendom College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (43, 'A teacher, podcaster, and co-founder of The Remnant Radio who facilitates discussions surrounding church history, constructive theology, and the operational boundaries of spiritual gifts.', 'Pastor, Teacher, Co-Founder of Remnant Radio', 'Master''s in Theology/Biblical Studies (or equivalent ministerial seminary training)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (44, 'A charismatic pastor, author, and co-host of The Remnant Radio who writes and teaches on the activation and evaluation of supernatural spiritual gifts within local church networks.', 'Charismatic Pastor, Author, Co-Host of Remnant Radio', 'Master of Divinity (M.Div.) from Southern Baptist Theological Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (45, 'A pastor and apologist who runs the BibleThinker ministry, dedicated to producing meticulous, granular, verse-by-verse structural analyses of biblical texts and current social controversies.', 'Pastor, Apologist, Director of BibleThinker', 'Graduate of Calvary Chapel Bible College');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (46, 'A historical apologist and researcher who focuses on textual criticism, early church records, and verifying the internal consistency of the New Testament Gospels.', 'Historical Apologist, Researcher (Testify)', 'B.S. in Engineering (highly analytical self-taught textual researcher)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (47, 'A biblical scholar, author, and president of The Center for Faith, Sexuality & Gender who provides exegesis surrounding contemporary complex ethical, social, and relational topics.', 'Biblical Scholar, Author, President of The Center for Faith, Sexuality & Gender', 'Ph.D. in New Testament from University of Aberdeen, M.Div. from Talbot School of Theology');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (48, 'A New Zealand-born street evangelist, author, and founder of Living Waters who utilizes a distinct open-air interview method focused on applying the Ten Commandments to personal ethics.', 'Street Evangelist, Author, Founder of Living Waters', 'High school graduate, self-trained apologist');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (49, 'A public intellectual, corporate strategist, and creator/host of Closer to Truth who organizes comprehensive academic interviews regarding science, philosophy, and cosmology.', 'Creator/Host of Closer to Truth, Corporate Strategist, Neuroscientist', 'Ph.D. in Anatomy/Brain Research from UCLA, MBA from Sloan School of Management (MIT), B.S. in Human Biology from Johns Hopkins University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (50, 'A digital creator, music artist, and cultural commentator who provides news analysis, hip-hop culture critiques, and accessible apologetics tailored for young adult audiences.', 'Hip-Hop Artist, Digital Creator, Cultural Commentator', 'Self-taught media producer and digital outreach specialist');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (51, 'The founder and CEO of Got Questions Ministries, a platform dedicated to providing direct, systematic, biblically cross-referenced text answers to theological inquiries.', 'Founder and CEO of Got Questions Ministries', 'Master of Science in Christian Apologetics from Calvary Theological Seminary, Master of Divinity from Calvary University, B.A. from Calvary University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (52, 'A media analyst and director of Little Light Studios who constructs systematic video investigations analyzing the symbolic and subconscious messages within contemporary secular entertainment.', 'Media Analyst, Director of Little Light Studios', 'Media Production and Seventh-day Adventist theological studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (53, 'A professor of apologetics at Biola University, author, and speaker who conducts structured discussions and scholastic interviews exploring contemporary youth worldview formation and cultural engagement.', 'Associate Professor of Apologetics (Biola University), Author, Speaker', 'Ph.D. in Apologetics and Worldview Studies from Southern Baptist Theological Seminary, M.A. in Theology and M.A. in Philosophy from Talbot School of Theology');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (54, 'A researcher, author, and speaker who co-authored content analyzing the history and mechanics of alternative physics, ancient astronaut theories, and modern New Age spirituality following his departure from those networks.', 'Author, Speaker, Apologist (former New Age writer)', 'B.A. in Philosophy from York University');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (55, 'An apologist and open-air speaker who works alongside Cliffe Knechtle to conduct interactive religious forums and live cross-examinations on college campuses.', 'Apologist, Campus Evangelist', 'Studied at Davidson College (background in theology/business)');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (56, 'A professional apologist, teacher, and speaker with Stand to Reason who specializes in identifying and dissecting structural fallacies within popular arguments targeting the Christian worldview.', 'Professional Apologist, Speaker (Stand to Reason), Teacher', 'Master of Science in Education, Master of Arts in Philosophy from Southern Evangelical Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (57, 'A biblical scholar, linguist, theologian, and co-founder of BibleProject who specializes in literary design, ancient near-eastern contexts, and Hebrew Bible structure.', 'Biblical Scholar, Linguist, Theologian, Co-Founder of BibleProject', 'Ph.D. in Hebrew Bible and Jewish Studies from University of Wisconsin-Madison, M.Div. from Western Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (58, 'A broadcaster, author, and host of Wretched Radio and TV who utilizes a fast-paced, satirical commentary style to evaluate contemporary church trends and cultural developments from a traditional reformed theological perspective.', 'Radio and TV Host (Wretched), Author', 'Theological and speech communication studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (59, 'A staff apologist for Catholic Answers, author, and philosopher who specializes in formal debate, public speaking, and defending traditional Catholic dogmas against both secular and non-Catholic religious positions.', 'Staff Apologist (Catholic Answers), Author, Speaker, Philosopher', 'Master of Arts in Theology from Franciscan University of Steubenville, Master of Arts in Philosophy from Holy Apostles College and Seminary');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (60, 'A charismatic pastor, author, and leader of Hungry Generation ministry who produces a large library of digital content focused on the practice of deliverance, spiritual warfare, fasting, and charismatic lifestyle models.', 'Lead Pastor of HungryGen Church, Author, Speaker', 'Pastoral leadership and biblical theology studies');
INSERT INTO creator_bios (creator_id, bio, occupation, education) VALUES (61, 'A historical apologist, researcher, and central director with Apologetics Canada who focuses on the transmission history of the New Testament, textual criticism, and early church manuscripts.', 'Historical Apologist, Researcher, Director', 'Ph.D. candidate in New Testament and Early Christianity from University of Toronto, Master of Theological Studies from Tyndale Seminary');
